+    let artifact_path = root.join(artifact_rel);
+    let (status, detail, sha) = load_json(&artifact_path).map_or_else(
+        || {
+            (
+                Signal::NoData,
+                format!("Artifact not found: {artifact_rel}"),
+                None,
