+        },
+        |v| {
+            let (sig, det) = check(&v);
+            let sha = sha256_file(&artifact_path);
+            (sig, det, sha)
+        },
+    );
+    CertEvidence {
+        gate: gate.to_string(),
+        bead: bead.to_string(),
+        status,
+        detail,
+        artifact_path: Some(artifact_rel.to_string()),
+        artifact_sha256: sha,
+    }
+}
